1	import { describe, expect, test } from "bun:test";
2	import { execSync, execFileSync } from "node:child_process";
3	import { existsSync, mkdtempSync, rmSync, writeFileSync, readFileSync } from "node:fs";
4	import { tmpdir } from "node:os";
5	import { join } from "node:path";
6	import { REPO_ROOT } from "./helpers";
7	
8	/**
9	 * Trust gate e2e (tmux-based). Exercises the first-run workspace trust dialog
10	 * and the Bypass Permissions mode acceptance dialog â€” the security-critical
11	 * gates that the rest of the e2e suite deliberately pre-seeds/skips.
12	 *
13	 * Each test boots the BUILT dist/cli.js inside tmux against a FRESH temp HOME
14	 * seeded with `hasCompletedOnboarding:true` (so the theme picker / security
15	 * notes are skipped) but with NO trust and NO skipDangerousModePermissionPrompt
16	 * for the project â€” so the trust dialog (and, with --dangerously-skip-permissions,
17	 * the bypass dialog) MUST appear.
18	 *
19	 * Gated out of CI (needs tmux + model creds).
20	 */
21	
22	const BIN = process.env.OCC_ENTRYPOINT ?? `${REPO_ROOT}/dist/cli.js`;
23	const SESSION = "occ-trust-test";
24	
25	function tmux(args: string[]): string {
26	  try {
27	    return execFileSync("tmux", args, { encoding: "utf8", timeout: 10_000 });
28	  } catch {
29	    return "";
30	  }
31	}
32	
33	function sessionAlive(): boolean {
34	  try {
35	    return execSync("tmux list-sessions 2>/dev/null", { encoding: "utf8" }).includes(SESSION);
36	  } catch {
37	    return false;
38	  }
39	}
40	
41	/** A fresh temp HOME seeded to skip onboarding but NOT trust / bypass acceptance. */
42	function freshSeededHome(): string {
43	  const home = mkdtempSync(join(tmpdir(), "occ-trust-"));
44	  writeFileSync(
45	    join(home, ".claude.json"),
46	    JSON.stringify({
47	      numStartups: 1,
48	      firstStartTime: "2026-07-06T00:00:00.000Z",
49	      migrationVersion: 11,
50	      userID: "occ-trust-seed-0000000000000000000000000000000000000000000000aa",
51	      hasCompletedOnboarding: true,
52	      lastOnboardingVersion: "2.1.200",
53	      lastReleaseNotesSeen: "2.1.200",
54	      projects: {},
55	    }),
56	  );
57	  return home;
58	}
59	
60	function startRepl(home: string, extraArgs: string[] = []) {
61	  execSync(`tmux kill-session -t ${SESSION} 2>/dev/null; true`);
62	  const envStr = Object.entries(process.env)
63	    .filter(([k]) => k.startsWith("ANTHROPIC"))
64	    .map(([k, v]) => `${k}='${v}'`)
65	    .join(" ");
66	  const args = extraArgs.join(" ");
67	  execSync(
68	    `tmux new-session -d -s ${SESSION} -x 200 -y 50 "env HOME='${home}' ${envStr} ${BIN} ${args}"`,
69	    { timeout: 5_000 },
70	  );
71	}
72	
73	function killRepl() {
74	  execSync(`tmux kill-session -t ${SESSION} 2>/dev/null; true`);
75	}
76	
77	function sendKeys(keys: string) {
78	  tmux(["send-keys", "-t", SESSION, ...keys.split(" ")]);
79	}
80	
81	function capturePane(): string {
82	  return tmux(["capture-pane", "-t", SESSION, "-p", "-S", "-"]);
83	}
84	
85	/** Poll capture-pane until `substr` appears or timeout. */
86	async function waitForText(substr: string, timeoutMs = 20_000): Promise<boolean> {
87	  const deadline = Date.now() + timeoutMs;
88	  while (Date.now() < deadline) {
89	    if (capturePane().toLowerCase().includes(substr.toLowerCase())) return true;
90	    await new Promise((r) => setTimeout(r, 200));
91	  }
92	  return false;
93	}
94	
95	/** Poll until the tmux session is gone (the CLI exited). */
96	async function waitForExit(timeoutMs = 10_000): Promise<boolean> {
97	  const deadline = Date.now() + timeoutMs;
98	  while (Date.now() < deadline) {
99	    if (!sessionAlive()) return true;
100	    await new Promise((r) => setTimeout(r, 200));
101	  }
102	  return false;
103	}
104	
105	function readSettingsTrust(home: string): { trust?: boolean; bypass?: boolean } {
106	  const cfgPath = join(home, ".claude.json");
107	  const settingsPath = join(home, ".claude", "settings.json");
108	  const out: { trust?: boolean; bypass?: boolean } = {};
109	  if (existsSync(cfgPath)) {
110	    try {
111	      const cfg = JSON.parse(readFileSync(cfgPath, "utf8"));
112	      const projects = cfg.projects ?? {};
113	      // trust is stored per-project; find any project with the flag.
114	      for (const k of Object.keys(projects)) {
115	        if (projects[k]?.hasTrustDialogAccepted) out.trust = true;
116	      }
117	    } catch {}
118	  }
119	  if (existsSync(settingsPath)) {
120	    try {
121	      out.bypass = !!JSON.parse(readFileSync(settingsPath, "utf8")).skipDangerousModePermissionPrompt;
122	    } catch {}
123	  }
124	  return out;
125	}
