127	describe.skipIf(!!process.env.CI || !process.env.ANTHROPIC_API_KEY)("Trust gate (tmux e2e, fresh HOME)", () => {
128	  test("fresh project shows trust dialog; default Enter accepts â†’ prompt", async () => {
129	    const home = freshSeededHome();
130	    startRepl(home);
131	    try {
132	      expect(await waitForText("Quick safety check", 20_000)).toBe(true);
133	      const pane = capturePane();
134	      expect(pane).toContain("Yes, I trust this folder");
135	      expect(pane).toContain("No, exit");
136	
137	      // Default cursor is on "Yes" (first option) â†’ Enter accepts.
138	      sendKeys("Enter");
139	      expect(await waitForText("for shortcuts", 15_000)).toBe(true);
140	
141	      // Trust persisted to .claude.json
142	      expect(readSettingsTrust(home).trust).toBe(true);
143	    } finally {
144	      killRepl();
145	      rmSync(home, { recursive: true, force: true });
146	    }
147	  }, 60_000);
148	
149	  test("second boot in same HOME skips the trust dialog", async () => {
150	    const home = freshSeededHome();
151	    startRepl(home);
152	    try {
153	      expect(await waitForText("Quick safety check", 20_000)).toBe(true);
154	      sendKeys("Enter"); // accept
155	      expect(await waitForText("for shortcuts", 15_000)).toBe(true);
156	      killRepl();
157	
158	      // Reboot in the same HOME â€” trust already persisted.
159	      startRepl(home);
160	      expect(await waitForText("for shortcuts", 15_000)).toBe(true);
161	      expect(capturePane().toLowerCase()).not.toContain("quick safety check");
162	    } finally {
163	      killRepl();
164	      rmSync(home, { recursive: true, force: true });
165	    }
166	  }, 60_000);
167	
168	  test("'No, exit' exits the session", async () => {
169	    const home = freshSeededHome();
170	    startRepl(home);
171	    try {
172	      expect(await waitForText("Quick safety check", 20_000)).toBe(true);
173	      sendKeys("Down"); // move to "No, exit"
174	      sendKeys("Enter");
175	      expect(await waitForExit(10_000)).toBe(true);
176	      // Decline must NOT persist trust.
177	      expect(readSettingsTrust(home).trust).not.toBe(true);
178	    } finally {
179	      killRepl();
180	      rmSync(home, { recursive: true, force: true });
181	    }
182	  }, 40_000);
183	
184	  test("bypass dialog: default cursor = 'No, exit'; Enter exits, no persist", async () => {
185	    const home = freshSeededHome();
186	    startRepl(home, ["--dangerously-skip-permissions"]);
187	    try {
188	      // Trust dialog first (always shown).
189	      expect(await waitForText("Quick safety check", 20_000)).toBe(true);
190	      sendKeys("Enter"); // accept trust
191	      // Bypass dialog next.
192	      expect(await waitForText("Bypass Permissions mode", 15_000)).toBe(true);
193	      const pane = capturePane();
194	      expect(pane).toContain("No, exit");
195	      expect(pane).toContain("Yes, I accept");
196	      // Default cursor is "No, exit" â†’ Enter declines â†’ exit.
197	      sendKeys("Enter");
198	      expect(await waitForExit(10_000)).toBe(true);
199	      expect(readSettingsTrust(home).bypass).not.toBe(true);
200	    } finally {
201	      killRepl();
202	      rmSync(home, { recursive: true, force: true });
203	    }
204	  }, 60_000);
205	
206	  test("bypass accept persists (one-time); second boot skips bypass dialog", async () => {
207	    const home = freshSeededHome();
208	    startRepl(home, ["--dangerously-skip-permissions"]);
209	    try {
210	      expect(await waitForText("Quick safety check", 20_000)).toBe(true);
211	      sendKeys("Enter"); // accept trust
212	      expect(await waitForText("Bypass Permissions mode", 15_000)).toBe(true);
213	      sendKeys("Down"); // move to "Yes, I accept"
214	      sendKeys("Enter");
215	      // Bypass-mode prompt footer contains "shift+tab".
216	      expect(await waitForText("shift+tab", 15_000)).toBe(true);
217	      expect(readSettingsTrust(home).bypass).toBe(true);
218	      killRepl();
219	
220	      // Reboot: trust + bypass acceptance persisted â†’ straight to bypass prompt.
221	      startRepl(home, ["--dangerously-skip-permissions"]);
222	      expect(await waitForText("shift+tab", 15_000)).toBe(true);
223	      expect(capturePane().toLowerCase()).not.toContain("bypass permissions mode");
224	    } finally {
225	      killRepl();
226	      rmSync(home, { recursive: true, force: true });
227	    }
228	  }, 60_000);
229	});
